const searches = [
  { query: 'Customer Success', aroundQuery: 'Europe' },
  { query: 'Operations Manager', aroundQuery: 'Netherlands' },
  { query: 'Project Manager', aroundQuery: 'Germany' },
  { query: 'Business Development', aroundQuery: 'Europe' },
  { query: 'Business Analyst', aroundQuery: 'United Kingdom' }
];

return searches.map(s => ({
  json: {
    url: `https://api.welcometothejungle.com/api/v1/jobs?query=${encodeURIComponent(s.query)}&around_query=${encodeURIComponent(s.aroundQuery)}&contract_type=full_time&page=1&per_page=20`,
    source_platform: 'wttj'
  }
}));

const response = $input.first().json;
const jobs = response.jobs || response.data || response.results || [];

return jobs.map(job => ({
  json: {
    job_id: job.slug || job.id || '',
    job_title: job.name || job.title || '',
    company: (job.organization && job.organization.name) || job.company || '',
    location: (job.office && job.office.city) || job.location || 'Europe',
    job_url: job.url || `https://www.welcometothejungle.com/jobs/${job.slug}`,
    description: (job.description || job.profile || '').replace(/<[^>]+>/g, ' ').trim().substring(0, 3000),
    source_platform: 'wttj'
  }
}));

const seen = $getWorkflowStaticData('global');
if (!seen.wttjSeenIds) seen.wttjSeenIds = [];

const item = $input.first().json;
if (seen.wttjSeenIds.includes(item.job_id)) return [];

seen.wttjSeenIds.push(item.job_id);
if (seen.wttjSeenIds.length > 2000) seen.wttjSeenIds = seen.wttjSeenIds.slice(-1000);

return [{ json: item }];
